).Add(0)\n51: \t}\n52: \n53: \treturn counter\n54: }\n55: \n56: func buildLabelSets(labels []string, labelValues map[string][]string) []prometheus.Labels {\n57: \tvar labelSets []prometheus.Labels\n58: \n59: \tvar n func(i int, ls prometheus.Labels)\n60: \tn = func(i int, ls prometheus.Labels) {\n61: \t\tif i == len(labels) {\n62: \t\t\tlabelSets = append(labelSets, ls)\n63: \t\t\treturn\n64: \t\t}\n65: \n66: \t\tlabel := labels[i]\n67: \t\tvalues := labelValues[label]\n68: \n69: \t\tfor _, v := range values {\n70: \t\t\tlsCopy := copyLabelSet(ls)\n71: \t\t\tlsCopy[label] = v\n72: \t\t\tn(i+1, lsCopy)\n73: \t\t}\n74: \t}\n75: \n76: \tn(0, prometheus.Labels{})\n77: \treturn labelSets\n78: }\n79: \n80: func copyLabelSet(ls prometheus.Labels) prometheus.Labels {\n81: \tnewLs := make(prometheus.Labels, len(ls))\n82: \tfor l, v := range ls {\n83: \t\tnewLs[l] = v\n84: \t}\n85: \treturn newLs\n86: }\n87: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/grafana--v11.4.0@44ec24e07ee8516b9c8fa339444e5ba064fad63d/-/blob/pkg/infra/metrics/metricutil/utils.go"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: package metricutil
