35: // NewCounterStartingAtZero initializes a new Prometheus counter with an initial
36: // observation of zero. Used for to guarantee the existence of the specific metric.
37: func NewCounterStartingAtZero(opts prometheus.CounterOpts) prometheus.Counter {
38: 	counter := prometheus.NewCounter(opts)
39: 	counter.Add(0)
40: 	return counter
41: }
