43: // NewCounterVecStartingAtZero initializes a new Prometheus counter with an initial
44: // observation of zero for every possible value of each label. Used for the sake of
45: // consistency among all the possible labels and values.
46: func NewCounterVecStartingAtZero(opts prometheus.CounterOpts, labels []string, labelValues map[string][]string) *prometheus.CounterVec {
47: 	counter := prometheus.NewCounterVec(opts, labels)
48: 
49: 	for _, ls := range buildLabelSets(labels, labelValues) {
50: 		counter.With(ls).Add(0)
51: 	}
52: 
53: 	return counter
54: }
